INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (1, 'Workplace Safety', 10);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (2, 'Labor Rights', 20);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (3, 'Health & Hygiene', 30);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (4, 'Environmental Compliance', 40);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (5, 'Anti-Harassment', 50);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (6, 'Fire Safety', 60);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (7, 'Chemical Handling', 70);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (8, 'Worker Welfare', 80);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (9, 'Quality Assurance', 90);
INSERT INTO mdl_course_categories (id, name, sortorder) VALUES (10, 'Management Training', 100);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (2, 1, 'Fundamentals of Occupational Health and Safety', 'Fundamentals of Occupational H', 'This introductory module covers the core principles of workplace safety, including hazard identification, risk assessment methodologies, and the legal frameworks governing employee protection in garment manufacturing.', 'topics', 1, 1, 1755528631, 1755528631);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (3, 1, 'Preventive Maintenance and Hazardous Material Handling', 'Preventive Maintenance and Haz', 'Learn essential protocols for maintaining industrial machinery safely and proper procedures for storing and disposing of chemicals, flammables, and hazardous waste commonly found in textile production.', 'topics', 1, 1, 1746081712, 1746081712);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (4, 1, 'Fire Safety, Emergency Evacuation, and First Aid', 'Fire Safety, Emergency Evacuat', 'A critical course dedicated to mastering fire suppression systems, executing structured evacuation drills, and providing immediate first aid in high-density factory environments.', 'topics', 1, 1, 1736931328, 1736931328);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (5, 1, 'Ergonomics and Musculoskeletal Disorder Prevention', 'Ergonomics and Musculoskeletal', 'Designed to address physical safety in repetitive motion jobs, this training focuses on proper lifting techniques, workstation adjustments, and strategies to prevent long-term back and joint injuries.', 'topics', 1, 1, 1717981569, 1717981569);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (6, 1, 'Safe Electrical Practices and Lockout/Tagout Procedures', 'Safe Electrical Practices and ', 'This specialized training ensures compliance with electrical safety standards, detailing the correct protocols for lockout/tagout during maintenance to prevent accidental energization of equipment.', 'topics', 1, 1, 1769507597, 1769507597);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (7, 2, 'Industrial Labor Law and Contract Compliance', 'Industrial Labor Law and Contr', 'This foundational course covers essential labor rights, including minimum wage standards, working hour limits, and contract negotiation strategies specifically tailored to the garment manufacturing industry.', 'topics', 1, 1, 1767974268, 1767974268);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (8, 2, 'Health, Safety, and Ergonomics in Textile Production', 'Health, Safety, and Ergonomics', 'Participants will learn to identify common workplace hazards in garment factories, implement proper safety protocols, and apply ergonomic solutions to prevent repetitive strain injuries among production staff.', 'topics', 1, 1, 1757843155, 1757843155);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (9, 2, 'Collective Bargaining and Union Relations', 'Collective Bargaining and Unio', 'This advanced module guides managers on conducting transparent meetings, understanding collective bargaining processes, and maintaining positive relationships with union representatives while ensuring fair treatment for all employees.', 'topics', 1, 1, 1713281840, 1713281840);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (10, 2, 'Discipline, Grievance Handling, and Due Process', 'Discipline, Grievance Handling', 'Learn the legal and ethical procedures for addressing employee grievances, conducting fair disciplinary investigations, and resolving conflicts in compliance with local labor regulations.', 'topics', 1, 1, 1743737020, 1743737020);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (11, 2, 'Gender Equity and Anti-Harassment Policies', 'Gender Equity and Anti-Harassm', 'An interactive session focused on preventing sexual harassment, promoting workplace diversity, and establishing clear reporting mechanisms to protect the dignity and rights of all workers in the factory environment.', 'topics', 1, 1, 1753384454, 1753384454);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (12, 3, 'Industrial Hygiene and Hazard Identification', 'Industrial Hygiene and Hazard ', 'This course provides comprehensive training on recognizing chemical, physical, and biological hazards specific to garment manufacturing. Participants will learn the proper application of the Hierarchy of Controls to eliminate or mitigate risks in production environments.', 'topics', 1, 1, 1754462823, 1754462823);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (13, 3, 'OSHA-Compliant Respiratory Protection and Fume Exhaust Systems', 'OSHA-Compliant Respiratory Pro', 'Designed for workers in dyeing and finishing units, this module covers the safe use of respirators, understanding ventilation mechanics, and recognizing signs of airborne exposure. It emphasizes compliance with occupational safety standards to prevent long-term health issues.', 'topics', 1, 1, 1738296882, 1738296882);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (14, 3, 'Ergonomics and Musculoskeletal Disorder Prevention', 'Ergonomics and Musculoskeletal', 'This interactive session addresses common physical strain associated with repetitive stitching and manual handling tasks. Workers will gain skills in adjusting workstations, using proper lifting techniques, and implementing micro-break strategies to reduce injury rates.', 'topics', 1, 1, 1712484515, 1712484515);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (15, 3, 'Sustainable Cleaning Protocols and Chemical Safety', 'Sustainable Cleaning Protocols', 'Focusing on eco-friendly cleaning practices, this course trains staff on the correct dilution and handling of industrial detergents. It includes practical demonstrations on safety data sheet (SDS) interpretation and the safe disposal of wastewater to protect both workers and the facility.', 'topics', 1, 1, 1766578102, 1766578102);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (16, 3, 'Advanced Hand Sanitation and Cross-Contamination Control', 'Advanced Hand Sanitation and C', 'This module is tailored for food-grade packaging and direct-contact garment lines, detailing high-touch surface sanitation and personal hygiene standards. Participants will learn the critical role of hygiene in preventing the spread of pathogens during production.', 'topics', 1, 1, 1740938662, 1740938662);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (17, 4, 'Introduction to Environmental Regulations and Standards', 'Introduction to Environmental ', 'This foundational course provides an overview of key international and local environmental laws applicable to garment manufacturing, including waste management and emissions standards.', 'topics', 1, 1, 1746191575, 1746191575);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (18, 4, 'Water Conservation and Effluent Treatment Systems', 'Water Conservation and Effluen', 'Learn practical strategies for reducing water usage in dyeing and finishing processes, plus a deep dive into operating and monitoring on-site effluent treatment plants.', 'topics', 1, 1, 1758927409, 1758927409);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (19, 4, 'Chemical Safety and Hazardous Waste Management', 'Chemical Safety and Hazardous ', 'This module covers the safe handling, storage, and disposal of hazardous chemicals used in textile production, ensuring full compliance with chemical safety protocols.', 'topics', 1, 1, 1766445788, 1766445788);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (20, 4, 'Energy Efficiency and Sustainable Manufacturing Practices', 'Energy Efficiency and Sustaina', 'Explore methods to optimize energy consumption in sewing lines and machinery, alongside initiatives that reduce the factory''s overall carbon footprint.', 'topics', 1, 1, 1765083502, 1765083502);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (21, 4, 'Internal Auditing and Continuous Compliance Improvement', 'Internal Auditing and Continuo', 'Develop skills to conduct internal environmental audits, identify non-conformities, and implement corrective actions to maintain and enhance regulatory compliance.', 'topics', 1, 1, 1762876738, 1762876738);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (22, 5, 'Foundations of Workplace Respect', 'Foundations of Workplace Respe', 'This introductory module defines the boundaries of acceptable behavior and explores the impact of harassment on workplace culture and employee well-being.', 'topics', 1, 1, 1740120193, 1740120193);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (23, 5, 'Recognizing and Reporting Harassment', 'Recognizing and Reporting Hara', 'Participants learn to identify subtle and overt signs of harassment, understand the reporting procedures, and know how to document incidents effectively.', 'topics', 1, 1, 1762444309, 1762444309);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (24, 5, 'Bystander Intervention Strategies', 'Bystander Intervention Strateg', 'An interactive session empowering staff to safely intervene when witnessing misconduct, providing techniques to de-escalate situations without escalating tension.', 'topics', 1, 1, 1722692980, 1722692980);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (25, 5, 'Inclusive Leadership for Management', 'Inclusive Leadership for Manag', 'Designed for supervisors, this course focuses on preventing team harassment, modeling inclusive behavior, and managing employees who engage in inappropriate conduct.', 'topics', 1, 1, 1731146461, 1731146461);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (26, 5, 'Protecting Vulnerable Populations', 'Protecting Vulnerable Populati', 'A specialized track addressing unique challenges faced by women, LGBTQ+ individuals, and marginalized groups within the garment manufacturing environment.', 'topics', 1, 1, 1710865588, 1710865588);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (27, 6, 'Fundamentals of Fire Prevention in Manufacturing', 'Fundamentals of Fire Preventio', 'This comprehensive introductory course covers the basics of fire safety protocols specific to garment factories, including hazard identification, evacuation procedures, and the importance of maintaining clear egress paths.', 'topics', 1, 1, 1763994547, 1763994547);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (28, 6, 'Operational Fire Extinguisher and Appliance Use', 'Operational Fire Extinguisher ', 'Employees will gain hands-on training in the correct operation of fire extinguishers and emergency suppression systems, with a focus on selecting the appropriate equipment for different types of ignition sources found in textile workshops.', 'topics', 1, 1, 1763209513, 1763209513);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (29, 6, 'High-Risk Material Handling and Combustible Storage', 'High-Risk Material Handling an', 'This module addresses the unique risks associated with storing and handling flammable materials such as synthetic fibers, dyes, and solvents, emphasizing proper labeling, storage density limits, and segregation techniques.', 'topics', 1, 1, 1740894653, 1740894653);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (30, 6, 'Emergency Response and Evacuation Drills', 'Emergency Response and Evacuat', 'Participants learn the critical skills needed to lead and follow during a fire emergency, including assembly point management, headcounts, and communication protocols to ensure the safety of all personnel on the factory floor.', 'topics', 1, 1, 1735509956, 1735509956);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (31, 6, 'Fire Alarm System Operation and Reporting', 'Fire Alarm System Operation an', 'This course trains staff on how to interact with the factory''s fire detection and alarm systems, covering sound signal recognition, initial incident reporting, and the proper coordination with external fire services during an active emergency.', 'topics', 1, 1, 1739859415, 1739859415);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (32, 7, 'Introduction to Chemical Safety and Classification', 'Introduction to Chemical Safet', 'This foundational course covers the fundamental principles of hazardous chemical identification, including understanding GHS labels, hazard statements, and pictograms to ensure immediate safety awareness.', 'topics', 1, 1, 1713122674, 1713122674);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (33, 7, 'Respiratory Protection and Ventilation Systems', 'Respiratory Protection and Ven', 'Learners will gain practical skills on selecting appropriate respiratory equipment, conducting fit tests, and maintaining industrial ventilation systems specifically designed for textile processing environments.', 'topics', 1, 1, 1726557782, 1726557782);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (34, 7, 'Spill Response and Containment Procedures', 'Spill Response and Containment', 'This hands-on training instructs employees on the correct use of spill kits, neutralization agents, and containment barriers to effectively manage accidental chemical releases in production areas.', 'topics', 1, 1, 1763876693, 1763876693);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (35, 7, 'Chemical Storage and Inventory Management', 'Chemical Storage and Inventory', 'Participants learn best practices for organizing storage cabinets, maintaining segregation protocols for incompatible substances, and performing accurate inventory audits to prevent cross-contamination.', 'topics', 1, 1, 1735389710, 1735389710);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (36, 7, 'Waste Disposal Compliance and Environmental Protocols', 'Waste Disposal Compliance and ', 'The course details the regulatory requirements for sorting, labeling, and disposing of chemical waste in alignment with local environmental laws and corporate sustainability goals.', 'topics', 1, 1, 1769618337, 1769618337);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (37, 8, 'Occupational Health and Safety Fundamentals', 'Occupational Health and Safety', 'Participants will learn to identify common hazards in garment production, understand OSHA compliance standards, and master emergency evacuation procedures to ensure a safe work environment.', 'topics', 1, 1, 1756591505, 1756591505);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (38, 8, 'Ergonomics and Injury Prevention Strategies', 'Ergonomics and Injury Preventi', 'This course covers proper lifting techniques, workstation setup optimization, and strategies to reduce musculoskeletal disorders among long-term sewing line employees.', 'topics', 1, 1, 1713831129, 1713831129);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (39, 8, 'Thermal Comfort and Heat Stress Management', 'Thermal Comfort and Heat Stres', 'Learn to recognize symptoms of heat-related illness, utilize cooling break protocols effectively, and implement hydration schedules to maintain productivity in high-temperature zones.', 'topics', 1, 1, 1765324076, 1765324076);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (40, 8, 'Chemical Safety and Hazardous Material Handling', 'Chemical Safety and Hazardous ', 'Employees will gain expertise in reading Safety Data Sheets (SDS), using personal protective equipment (PPE) correctly, and responding to spills involving detergents, solvents, and flammables.', 'topics', 1, 1, 1732330220, 1732330220);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (41, 8, 'Workplace Violence Prevention and De-escalation', 'Workplace Violence Prevention ', 'This training focuses on recognizing warning signs of aggression, establishing zero-tolerance policies, and applying non-violent communication techniques to resolve interpersonal conflicts peacefully.', 'topics', 1, 1, 1727330281, 1727330281);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (42, 9, 'Fundamentals of Garment Quality Control', 'Fundamentals of Garment Qualit', 'This foundational course introduces the essential terminology, inspection standards, and quality hierarchy specific to the garment manufacturing industry, providing a clear understanding of how defects impact product reputation.', 'topics', 1, 1, 1772674142, 1772674142);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (43, 9, 'Advanced Defect Identification and Root Cause Analysis', 'Advanced Defect Identification', 'Participants will learn to systematically identify complex weaving and sewing defects while applying the ''5 Whys'' method and Fishbone diagrams to analyze process failures, enabling proactive prevention rather than reactive correction.', 'topics', 1, 1, 1729383686, 1729383686);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (44, 9, 'Statistical Process Control for Textile Production', 'Statistical Process Control fo', 'This technical module teaches QA professionals how to utilize Control Charts and SPC tools to monitor thread tension, stitch density, and fabric consistency, ensuring production remains within statistically defined limits to maintain high quality output.', 'topics', 1, 1, 1730217550, 1730217550);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (45, 9, 'Supplier Quality Management and Incoming Material Inspection', 'Supplier Quality Management an', 'Focuses on establishing rigorous criteria for evaluating fabric, trims, and accessories, covering techniques for sample inspection, acceptance testing, and managing supplier non-conformance reports to minimize material-related defects.', 'topics', 1, 1, 1721456097, 1721456097);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (46, 9, 'ISO 9001 Implementation for Garment Factories', 'ISO 9001 Implementation for Ga', 'A comprehensive program guiding teams through the documentation, audit preparation, and continuous improvement cycles required for ISO 9001 certification, ensuring the factory meets international standards for quality management systems.', 'topics', 1, 1, 1743224555, 1743224555);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (47, 10, 'Foundations of Garment Operations', 'Foundations of Garment Operati', 'This comprehensive module introduces new hires to the fundamental processes of garment manufacturing, from fabric handling to final assembly. Participants learn to identify key quality standards and understand the workflow efficiency critical for factory performance.', 'topics', 1, 1, 1743575130, 1743575130);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (48, 10, 'Lean Manufacturing and Waste Reduction', 'Lean Manufacturing and Waste R', 'Learn to apply Lean Six Sigma principles to eliminate bottlenecks and reduce material waste in the cutting and sewing sections. This course focuses on practical techniques for improving production flow and maximizing machine uptime.', 'topics', 1, 1, 1728682684, 1728682684);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (49, 10, 'Quality Control and Compliance Auditing', 'Quality Control and Compliance', 'Equip managers and supervisors with the skills to conduct effective internal audits aligned with ISO standards and international retail requirements. You will master the use of checklists for defect identification and correct immediate corrective actions.', 'topics', 1, 1, 1751280988, 1751280988);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (50, 10, 'Sustainable Textile Practices and Safety', 'Sustainable Textile Practices ', 'Explore the latest protocols for chemical safety, fire prevention, and eco-friendly dyeing processes in a high-volume environment. This training ensures adherence to OSHA regulations while promoting a culture of workplace sustainability.', 'topics', 1, 1, 1728870426, 1728870426);
INSERT INTO mdl_course (id, category, fullname, shortname, summary, format, visible, enablecompletion, timecreated, timemodified) VALUES (51, 10, 'Inventory Management and Supply Chain Logistics', 'Inventory Management and Suppl', 'Master the art of just-in-time (JIT) inventory control to prevent stockouts or overstocking in a fast-paced factory setting. Participants will learn to utilize ERP systems for real-time tracking of raw materials and finished goods.', 'topics', 1, 1, 1728331729, 1728331729);
